document.addEventListener("DOMContentLoaded",function(){const script=document.getElementById("django-issues-script");const MODAL_OVERLAY_ID="django-issues-modal-overlay";const FORM_CONTAINER_ID="django-issues-form-container";const OPENER_ID="issue-opener";const FORM_ID="django-issues-form";const SCREENSHOT_PREVIEW_CONTAINER_ID="screenshot-preview-container";const SCREENSHOT_PREVIEW_IMG_ID="screenshot-preview-img";const SCREENSHOT_LIBRARY=script.dataset.engine;const SUBMIT_URL=script.dataset.url;axios.defaults.xsrfHeaderName="X-CSRFTOKEN";axios.defaults.xsrfCookieName="csrftoken";function createModal(){if(document.getElementById(MODAL_OVERLAY_ID)){return}const modalOverlay=document.createElement("div");modalOverlay.id=MODAL_OVERLAY_ID;modalOverlay.className="modal-overlay";modalOverlay.style.display="none";const modalContent=document.createElement("div");modalContent.id=FORM_CONTAINER_ID;modalContent.className="modal-content";modalOverlay.appendChild(modalContent);document.body.appendChild(modalOverlay);modalOverlay.addEventListener("click",function(event){if(event.target===this){this.style.display="none"}})}const issueOpener=document.getElementById(OPENER_ID);if(issueOpener){issueOpener.addEventListener("click",function(){let screenshotPromise=Promise.resolve(null);if(SCREENSHOT_LIBRARY){if(SCREENSHOT_LIBRARY==="html2canvas"){screenshotPromise=html2canvas(document.body,{width:window.innerWidth,height:document.documentElement.scrollHeight,allowTaint:true,scale:1,foreignObjectRendering:true,useCORS:true}).then(canvas=>canvas.toDataURL("image/png"))}else if(SCREENSHOT_LIBRARY==="dom-to-image"){screenshotPromise=domtoimage.toPng(document.body)}}screenshotPromise.then(function(screenshotData){createModal();axios.get(SUBMIT_URL).then(response=>{const formContainer=document.getElementById(FORM_CONTAINER_ID);const modalOverlay=document.getElementById(MODAL_OVERLAY_ID);if(formContainer&&modalOverlay){formContainer.innerHTML=response.data;const screenshotInput=formContainer.querySelector('input[name="screenshot"]');const addScreenshotCheckbox=formContainer.querySelector('input[name="add_screenshot"]');const screenshotPreviewContainer=document.getElementById(SCREENSHOT_PREVIEW_CONTAINER_ID);const screenshotPreviewImg=document.getElementById(SCREENSHOT_PREVIEW_IMG_ID);if(SCREENSHOT_LIBRARY){screenshotInput.value=screenshotData;screenshotPreviewImg.src=screenshotData;function togglePreview(show){screenshotPreviewContainer.style.visibility=show?"visible":"hidden";screenshotPreviewContainer.style.opacity=show?"1":"0"}togglePreview(addScreenshotCheckbox.checked);addScreenshotCheckbox.addEventListener("change",function(){togglePreview(this.checked)})}else{if(screenshotInput)screenshotInput.remove();if(addScreenshotCheckbox)addScreenshotCheckbox.closest("p").remove();if(screenshotPreviewContainer)screenshotPreviewContainer.remove()}modalOverlay.style.display="flex"}}).catch(error=>{console.error("Error loading form:",error)})})});issueOpener.style.display="block"}document.addEventListener("submit",function(event){if(event.target.id===FORM_ID){event.preventDefault();const formData=new FormData(event.target);const data=Object.fromEntries(formData.entries());if(!data.add_screenshot){delete data.screenshot}axios.post(SUBMIT_URL,data,{headers:{"Content-Type":"application/json","X-CSRFToken":data.csrfmiddlewaretoken}}).then(response=>{if(response.data.success){const modalOverlay=document.getElementById(MODAL_OVERLAY_ID);if(modalOverlay){modalOverlay.style.display="none"}const formContainer=document.getElementById(FORM_CONTAINER_ID);if(formContainer){formContainer.innerHTML=""}alert("Issue submitted successfully!")}else{alert("Error: "+JSON.stringify(response.data.errors))}}).catch(error=>{if(error.response&&error.response.data&&error.response.data.errors){alert("Error: "+JSON.stringify(error.response.data.errors))}else{console.error("Error submitting form:",error);alert("An unexpected error occurred.")}})}});document.addEventListener("keydown",function(event){if(event.key==="Escape"){const modalOverlay=document.getElementById(MODAL_OVERLAY_ID);if(modalOverlay&&modalOverlay.style.display!=="none"){modalOverlay.style.display="none"}}})});
